func multiExpr(exprs []Expr) Expr {
	if len(exprs) == 1 {
		return exprs[0]
	}
	result := exprs[0]
	for _, e := range exprs[1:] {
		result = &ConcatExpr{Left: result, Right: e}
	}
	return result
}
